---@class LWordMaskTrie
local LWordMaskTrie = LxClass("LWordMaskTrie", nil)

local _ignoreChars = {"%"," ", "@", "&", "*","\'", "\\", "\"", "~", "!", "$", "-", "+", "[", "]", "{", "}", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_"}
local _ignoreChars_EA = {"%", "@", "&", "*","\'", "\\", "\"", "~", "!", "$", "-", "+", "[", "]", "{", "}", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_"}

local _invalidInput ={ "%","\n", "&","\'", "\\", "\"", "~", "!", "$", "-", "+", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_", "=", "’"}
local _invalidChars = { "%", "&","\'", "\\", "\"", "~", "!", "$", "-", "+", "[", "]", "{", "}", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_"}
local _invalidEasyChars = { "[", "]","%", "|","="}

local _FilterState = {
    VALID = 0,
    INVALID_WORD = 1,
    INVALID_CHAR = 2,
    INVALID_SPACE = 3,
}

