    INPUT = 1,
    Common = 2,
    Esay = 3,
}

function LWordMaskTrie:LWordMaskTrie()
    self._ignoreStrMap = {}
    self._trie_root = {}

    self._remoteReqs = {}
    self._remoteCacheList = {}
