---@region trie_tree
function LWordMaskTrie:InitTrie()
    if self._isInitTrie then return end
    self._isInitTrie = true
    self._ignoreStrMap = {}
    self._trie_root = {}
    self._isFrameEnding = false
    self._frameIndex = 1

    local isOther = gLGameLanguage:IsForeignRegion()
    self._isMatchWords = isOther

    if isOther then
        for k,v in ipairs(_ignoreChars_EA) do
            self._ignoreStrMap[v] = k
        end
    else
        for k,v in ipairs(_ignoreChars) do
            self._ignoreStrMap[v] = k
        end
    end
end

function LWordMaskTrie:FrameAddTrieFromTable()
    if not self._isInitTrie then return false end
    if self._isFrameEnding then return false end
    local startIndex = self._frameIndex
    self._frameIndex = startIndex + 300
    local endIndex = self._frameIndex - 1
    local refList = GameTable.TrieWordsRef
    if not self._frameMax then self._frameMax = #refList end
    if endIndex > self._frameMax then
        endIndex = self._frameMax
    end
    self:_TrieDict_Generate(refList, startIndex, endIndex)
    if endIndex >= self._frameMax then
        self._isFrameEnding = true
        if LOG_INFO_ENABLED then
            printInfoN("初始化屏蔽词完成")
        end
        if gLGameTable then gLGameTable:ClearTable("TrieWordsRef") end
        return false
    end
    return true
end


function LWordMaskTrie:AddWebWordList(worldList)
    if not self._isInitTrie then return end
    self:_TrieDict_Generate(worldList)
end

function LWordMaskTrie:_TrieDict_Generate(wordList, starIndex, endIndex)
    wordList = wordList or {}
    if not starIndex then starIndex = 1 end
    if not endIndex then endIndex = #wordList end

    local trie_dict = self._trie_root
    local ignoreStrMap = self._ignoreStrMap
    local word
    for k=starIndex, endIndex do
        word = wordList[k]
        local t = trie_dict
        local len = #word
        local byteLen = len
        local i = 1
        local endIdx = 0
        while true do
            if i > byteLen then
                break
            end
            local bLetterOrDigit = false

            local c = word:byte(i)
            if c >= 0x00 and c <= 0x7F then
                endIdx = i + 1
                bLetterOrDigit = (c >= 0x61 and c <=0x7A) or (c >= 0x41 and c <= 0x5A) or (c >= 0x30 and c <= 0x39)
            elseif c >= 0xC2 and c <= 0xDF then
                endIdx = i + 2
            elseif c >= 0xE0 and c <= 0xEF then
                endIdx = i + 3
            elseif c >= 0xF0 and c <= 0xF4 then
                endIdx = i + 4
            else --invalid
                endIdx = i + 1
            end

            local str = string.sub(word, i, endIdx - 1)
            if bLetterOrDigit then
                str = string.lower(str)
            end
            if not ignoreStrMap[str] then
                if not t[str] then
                    t[str] = {}
                end
                t = t[str]
            end
            i = endIdx
            if i > byteLen then
                t.ed = true
            end
        end
    end
end

function LWordMaskTrie:_TrieDict_Split(inStr)
    local tbl = {}
    local origin = {}
    local byteLen = #inStr
    local i = 1
    local endIdx = 0
    local ignoreStrMap = self._ignoreStrMap
    while true do
        if i > byteLen then
            break
        end
        local bLetterOrDigit = false
        local bLetter = false

        local c = inStr:byte(i)
        if c >= 0x00 and c <= 0x7F then
            endIdx = i + 1
            bLetter = (c >= 0x61 and c <=0x7A) or (c >= 0x41 and c <= 0x5A)
            bLetterOrDigit = bLetter or (c >= 0x30 and c <= 0x39)

        elseif c >= 0xC2 and c <= 0xDF then
            endIdx = i + 2
        elseif c >= 0xE0 and c <= 0xEF then
            endIdx = i + 3
        elseif c >= 0xF0 and c <= 0xF4 then
            endIdx = i + 4
        else --invalid
            endIdx = i + 1
        end

        local str = string.sub(inStr, i, endIdx - 1)
        local nstr = str
        if bLetterOrDigit then
            nstr = string.lower(nstr)
        end

        table.insert(tbl, {o=str, n=nstr, s=i, e=endIdx-1, i=ignoreStrMap[nstr], l=bLetter})
        table.insert(origin, str)

        i = endIdx
    end
    return tbl,origin
end

function LWordMaskTrie:_Ignore_Emoji_Check(strContentArr, originArr, ignoreEmojiMap)
    local sIdx = 0
    local id = 0
    local idstr = ""
    local retDatas = {}
    for k,v in ipairs(originArr) do
        if v == "#" then
            if sIdx > 0 and (k - sIdx) > 1 then
                idstr = table.concat(originArr, "", sIdx + 1, k - 1)
                if idstr and ignoreEmojiMap[idstr] then
                    local str = "#"..idstr.."#"
                    table.insert(retDatas, {o=str,n=str, s=sIdx, e=k, i = true})
                    sIdx = 0
                else
                    sIdx = k
                end
            else
                sIdx = k
            end
        end
    end
    local len = #retDatas
    for k=len, 1, -1 do
        local data = retDatas[k]
        local s = data.s
        local e = data.e
        local sData = strContentArr[s]
        local eData = strContentArr[e]
        data.s = sData.s
        data.e = eData.e
        for i=e, s, -1 do
            table.remove(strContentArr, i)
            table.remove(originArr, i)
        end
        table.insert(strContentArr, s, data)
        table.insert(originArr, s, data.o)
    end
end

function LWordMaskTrie:_TrieDict_CheckShield(strContent, bReplace, charsType, ignoreEmojiMap)
    local matchs = {}
    local strContentArr,originArr = self:_TrieDict_Split(strContent)
    if ignoreEmojiMap ~= nil then
        self:_Ignore_Emoji_Check(strContentArr,originArr, ignoreEmojiMap)
    end
    local len = #strContentArr
    local trie_dict = self._trie_root

    local holderByte = "*"

    local isMatchWords = self._isMatchWords -- 全字匹配， 词要被分割字符分割

    local isLastCharSpace = true
    --检查屏蔽词
    for k=1, len do
        local node = trie_dict
        local cur = k
        local hitCur = nil
        local hitNode = nil

        local bCheck = true
        if isMatchWords then -- 全字匹配模式， 上个字符必须为分割字符
            local curData = strContentArr[k]
            if curData.l and not isLastCharSpace then --当前字符是字母或者数字 且 上个字符不为分割字符， 不从该字符开始检查
                bCheck = false
            end
            isLastCharSpace = not curData.l --记录字符是否为分割字符
        end

        if bCheck then
            for i = k, len do
                local data = strContentArr[i]
                local c = data.n
                local ignore = data.i

                if ignore and i == k then --开头是忽略的符号不继续下一字符检查
                    cur = cur - 1
                    break
                end
                if not ignore then
                    local t = node[c]
                    if not t then --没有该字符的节点了，不继续下一字符检查了
                        cur = cur - 1
                        break
                    end
                    node = t
                    if t.ed then --是某个屏蔽词的结束字符，记录，但是为取最长屏蔽词，继续检查下一字符
                        hitCur = cur
                        hitNode = node
                    end
                end
                cur = cur + 1
            end
            if hitNode and hitNode.ed then
                if isMatchWords then --全词匹配需要判断最后字符的下一字符为分割字符 或语句结束
                    if hitCur == len or not strContentArr[hitCur + 1].l or not strContentArr[k].l then
                        table.insert(matchs, {s=k, e=hitCur, l = (hitCur - k + 1)})
                    end
                else
                    table.insert(matchs, {s=k, e=hitCur, l = (hitCur - k + 1)})
                end
            end
        end
    end

    local retState = nil
    if #matchs > 0 then
        retState = _FilterState.INVALID_WORD
        if LOG_INFO_ENABLED then
            for k,v in ipairs(matchs) do
                printErrorN("检测到"..tostring(strContent).."，含有屏蔽词"..table.concat(originArr , "" ,v.s, v.e))
            end
        end
        if not bReplace then
            return retState, strContent
        end

        --替换屏蔽词
        local s = 1
        local e = 0
        for k,v in ipairs(matchs) do
            if v.e > e then
                e = v.e
                s = math.max(s, v.s)
                for i=s,e do
                    originArr[i] = holderByte
                end
                s = e + 1
            end
        end
    end

    --检查特殊符号
    local matchLen = 0
    local charSet = self:GetInvalidCharSet(charsType)
    if charSet then
        for i = 1, len do
            local c = strContentArr[i].n
            if charSet[c] then
                matchLen = matchLen + 1
                if c == " " then
                    retState = _FilterState.INVALID_SPACE
                end
                if bReplace then
                    originArr[i] = holderByte
                end
            end
        end
    end

    if matchLen > 0 and not retState then
        retState = _FilterState.INVALID_CHAR
    end
    if retState then
        return retState, bReplace and table.concat(originArr) or strContent
    else
        return _FilterState.VALID, strContent
    end
end

function LWordMaskTrie:GetInvalidCharSet(charsType)
    if charsType == _CharsType.INPUT then
        if not self._inputCharMap then
            self._inputCharMap = {}
            for k,v in ipairs(_invalidInput) do
                self._inputCharMap[v] = true
            end
        end
        return self._inputCharMap
    elseif charsType == _CharsType.Common then
        if not self._commonCharMap then
            self._commonCharMap = {}
            for k,v in ipairs(_invalidChars) do
                self._commonCharMap[v] = true
            end
        end
        return self._commonCharMap
    elseif charsType == _CharsType.Esay then
        if not self._easyCharMap then
            self._easyCharMap = {}
            for k,v in ipairs(_invalidEasyChars) do
                self._easyCharMap[v] = true
            end
        end
        return self._easyCharMap
    end
    return nil
end
---@endregion trie_tree

---@region webCheck
function LWordMaskTrie:_RemoteFilterWorld(data)
    local id = self._remoteReqId + 1
    self._remoteReqId = id

    data.id = id

    local cacheData =  self._remoteCacheMap[data.content]
    if cacheData then
        self:_AfterRemoteResult(data, cacheData)
        return
    end

    table.insert(self._remoteReqs, data)
    if self._isRemoteReq then return end

    self:_NextRemoteReq()
end

function LWordMaskTrie:_NextRemoteReq()
    local len = #self._remoteReqs
    if len == 0 then
        self._isRemoteReq = false
        return
    end
    local data = self._remoteReqs[1]
    table.remove(self._remoteReqs, 1)

    local cacheData =  self._remoteCacheMap[data.content]
    if cacheData then
        self:_AfterRemoteResult(data, cacheData)
        self:_NextRemoteReq()
        return
    end
    MgrCenter.HttpMgr:DoPostByBody(data.url, data.body, data.headers, function(url, ret, result)
        self:_OnRemoteResult(data, ret, result)
        self:_NextRemoteReq()
    end)
end

function LWordMaskTrie:_OnRemoteResult(data, ret, result)
    if ret == 0 then
        self._remoteCacheMap[data.content] = result.content
        table.insert(self._remoteCacheList, data.content)
        if #self._remoteCacheList > 15 then
            local removeData = table.remove(self._remoteCacheList)
            self._remoteCacheList[removeData] = nil
        end
    end
    self:_AfterRemoteResult(data, (ret == 0 ) and result.content or data.content)
end

function LWordMaskTrie:_AfterRemoteResult(data, newContent)
    local oldContent = data.content
    local action = data.action
    local replace = data.replace
    local bFilter = oldContent ~= newContent
    if bFilter then
        action(_FilterState.INVALID_WORD, replace and newContent or oldContent, oldContent)
        return
    end
    self:_LocalFilterWord(oldContent, action, replace, data.charsType)
end
---@endregion webCheck
---@param content string @需要检测的字符串
---@param action fun(result:number, newstr:string, origin:string) @屏蔽结果调用啊含糊， result:VALID = 0,INVALID_WORD = 1,INVALID_CHAR = 2,INVALID_SPACE = 3,
---@param replace boolean @是否要把屏蔽词替换成*号
---@param charsType number @类型INPUT = 1,Common = 2 ，Esay = 3
---@param ignoreEmojiMap table<string,boolean> @ 检测emoji
function LWordMaskTrie:FilterWord(content, action, replace, charsType, ignoreEmojiMap)
    if self._isWebCheck and action ~= nil then
        local data = {content=content, action=action, replace=replace, charsType=charsType, ignoreEmojiMap = ignoreEmojiMap}
        self:_RemoteFilterWorld(data)
        return
    end
    return self:_LocalFilterWord(content, action, replace, charsType, ignoreEmojiMap)
end

function LWordMaskTrie:_LocalFilterWord(content, action, replace, charsType, ignoreEmojiMap)
    local filterResult,newContent = self:_TrieDict_CheckShield(content, replace, charsType, ignoreEmojiMap)
    if action ~= nil then
        action(filterResult, newContent, content)
        return
    end
    return filterResult, newContent, content
end

return LWordMaskTrie